    <>
      <div className="flex justify-end">
      <button size="sm" class="bg-blue-500 text-white px-4 py-2 rounded-md justify-end">
      Add
      </button>
      </div>
      <strong className="text-gray-700 font-medium">Предмет</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Курс</th>
              <th>Группа</th>
              <th>Специальност</th>
            </tr>
          </thead>
          <tbody>
            {groups.map(item => (
              <tr key={item._id}>
                <td>{item.kurs}</td>
                <td>{item.group_number}</td>
                <td>{item.speciality.speciality}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      </>

  );
};
